-- [ ObfusPro+ ]
local kNqrp = bit32 or bit or error("ObfusPro+: Environment error");
local function SdrBya(FExdp)
    local jctEUcfo = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    local SLsLL = string.gsub(FExdp, '[^' .. jctEUcfo .. ']', '')
    local vEIYZgR = {}
    for Ghvw = 1, #SLsLL, 4 do
        local HcC, XZc, Oid, KgN = string.byte(SLsLL, Ghvw, Ghvw + 3)
        if not HcC then break end
        local GNdE = string.find(jctEUcfo, string.char(HcC)) - 1
        local YHbK = string.find(jctEUcfo, string.char(XZc)) - 1
        local qaHL = Oid and string.find(jctEUcfo, string.char(Oid)) - 1 or 0
        local JMar = KgN and string.find(jctEUcfo, string.char(KgN)) - 1 or 0
        local mxjw = GNdE * 262144 + YHbK * 4096 + qaHL * 64 + JMar
        local HExk = kNqrp.band(kNqrp.rshift(mxjw, 16), 255)
        table.insert(vEIYZgR, string.char(kNqrp.bxor(HExk, 32)))
        if Oid and string.char(Oid) ~= '=' then
            HExk = kNqrp.band(kNqrp.rshift(mxjw, 8), 255)
            table.insert(vEIYZgR, string.char(kNqrp.bxor(HExk, 32)))
        end
        if KgN and string.char(KgN) ~= '=' then
            HExk = kNqrp.band(mxjw, 255)
            table.insert(vEIYZgR, string.char(kNqrp.bxor(HExk, 32)))
        end
    end
    return table.concat(vEIYZgR)
end
local wFPVQu = math.sin(318);
local ylKtxShn = [===[]===]
local rKHVtyj = SdrBya(ylKtxShn)
local KzWCMA = math.sin(251);
task.spawn(assert(loadstring(rKHVtyj)))
